import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Journeys Assist","description":"","frontmatter":{"title":"Journeys Assist","slug":"journeys-assist"},"headers":[],"relativePath":"marketer-hub/journeys-assist.md","filePath":"marketer-hub/journeys-assist.md"}'),s={name:"marketer-hub/journeys-assist.md"};function o(n,e,l,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Journeys Assist allows you to combine your powerful banners and interstitials from <a href="./journeys-overview.html">Journeys</a> with your mobile measurement capabilities of <a href="./ads-overview.html">Ads</a>, <a href="./branch-universal-email.html">Email</a> and other Branch-powered channels to provide complete attribution of the user flow.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p><strong>Same Session</strong> (Enabled by default)</p><ol><li><p>User lands on your mobile website and sees a banner or full-page interstitial promoting the mobile app coming from an ad, email interaction or other Branch powered channel.</p><ul><li>User can come from an ad they interact with (click).</li><li>User can come from an email campaign (click).</li></ul></li><li><p>User clicks the call to action to install the mobile app within the same session.</p></li><li><p>Once the user opens the app, conversions (including the install) that happen in the app, are attributed to the original Branch powered campaign the user interacted with.</p></li></ol><p><strong>Multi Session</strong></p><ol><li><p>User lands on your mobile website and sees a banner or full-page interstitial promoting the mobile app coming from an ad, email interaction or other Branch powered channel.</p><ul><li>User can come from an ad they interact with (click).</li><li>User can come from an email campaign (click).</li></ul></li><li><p>User drops off for some time and returns to the mobile website to see the Journeys banner/interstitial again.</p></li><li><p>User clicks the call to action to install the mobile app.</p></li><li><p>Once the user opens the app, conversions (including the install) that happen in the app, are attributed to the original Branch powered campaign the user interacted with.</p></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Journeys Assist, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enabled Journeys for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Implemented the Branch <a href="./web-sdk-overview.html">Web SDK</a> into your website.</p></li><li><p>Already running Journeys <a href="./create-journey-banner-or-interstitial.html">banners/interstitials</a>.</p></li><li><p>Already running other Branch powered channels, like ad campaigns through your chosen <a href="./ad-partners-list.html">ad partner</a> and/or running email campaigns through your chosen <a href="./email-partners-list.html">email partner</a>.</p></li></ol><h2 id="enabling-journeys-assist" tabindex="-1">Enabling Journeys Assist <a class="header-anchor" href="#enabling-journeys-assist" aria-label="Permalink to &quot;Enabling Journeys Assist&quot;">​</a></h2><h3 id="same-session" tabindex="-1"><strong>Same Session</strong> <a class="header-anchor" href="#same-session" aria-label="Permalink to &quot;**Same Session**&quot;">​</a></h3><p>This is enabled by default for all Journeys. If a user is driven to a mobile web session from a Branch powered channel and interacts with a Journey Banner within the same session, Branch will automatically bypass the Journey CTA link with the session&#39;s referring Branch Link.</p><h3 id="multi-session" tabindex="-1"><strong>Multi Session</strong> <a class="header-anchor" href="#multi-session" aria-label="Permalink to &quot;**Multi Session**&quot;">​</a></h3><p>If you wish to support Journeys Assist across multiple mobile web sessions to credit referring Branch powered channels for longer durations, you must work with your development team to add two new parameters to the web SDK initialization options.</p><p>See our <a href="./implement-journeys-assist.html">developer documentation</a> for implementation details.</p><h2 id="disabling-journeys-assist" tabindex="-1">Disabling Journeys Assist <a class="header-anchor" href="#disabling-journeys-assist" aria-label="Permalink to &quot;Disabling Journeys Assist&quot;">​</a></h2><p>If you wish to disable the default Same Session Journeys Assist support and have Journeys always claim attribution for post CTA click conversions, you must work with your development team to implement the necessary changes.</p><p>See our <a href="./implement-journeys-assist.html">developer documentation</a> for implementation details.</p><h2 id="view-analytics" tabindex="-1">View Analytics <a class="header-anchor" href="#view-analytics" aria-label="Permalink to &quot;View Analytics&quot;">​</a></h2><p>After enabling Journeys Assist and as campaigns run, your ad/email campaigns should receive credit through Journeys installs and other conversions. To do this, we can apply the add the <code>~tags</code> filter for your respective campaign. With this, you can view which Journeys campaign drove the ad/email conversion.</p><table tabindex="0"><thead><tr><th></th><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Dashboard Report Filter</td><td>tags</td><td>The view/creative name of your Journeys campaign.</td></tr><tr><td>Exports Key</td><td>Last Attributed Touch Data Tilde Journey Name</td><td>The view/creative name of your Journeys campaign.</td></tr></tbody></table><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Does Journeys Assist work with all types of ad networks?</summary><p>Journeys Assist only works with ad networks where a Branch Link is used for redirection. In other words, ad networks that solely rely on an MMP API connection to function will not utilize Journeys Assist.</p></details>',24)])])}const m=a(s,[["render",o]]);export{p as __pageData,m as default};
